          return res.status(404).json({ error: \`Protocol \${protocol} not found\` });
        }

        if (!handler[action]) {
          return res.status(400).json({ error: \`Action \${action} not supported for \${protocol}\` });
        }

        const result = await handler[action](req.body);
        res.json(result);
      } catch (error) {
        console.error('API Error:', error);
        res.status(500).json({ error: error.message });
      }
    });
  }

