    this.wss = new WebSocket.Server({ 
      port: ${config.server.port + 1},
      path: '/ws'
    });

    console.log(\`🔌 WebSocket server started on ws://localhost:\${${config.server.port + 1}}/ws\`);

    this.wss.on('connection', (ws, req) => {
      console.log('📱 New WebSocket client connected');

      ws.on('message', async (message) => {
        try {
          const data = JSON.parse(message);
          const response = await this.handleWebSocketMessage(data);
          ws.send(JSON.stringify(response));
        } catch (error) {
          console.error('WebSocket Error:', error);
          ws.send(JSON.stringify({
            error: error.message,
            timestamp: new Date().toISOString()
          }));
        }
      });

      ws.on('close', () => {
        console.log('📱 WebSocket client disconnected');
      });
    });
  }

  async handleWebSocketMessage(data) {
    const { protocol, command, ...params } = data;

    const handler = this.protocolHandlers.get(protocol);
    if (!handler) {
      throw new Error(\`Protocol \${protocol} not found\`);
    }

    if (!handler[command]) {
      throw new Error(\`Command \${command} not supported for \${protocol}\`);
    }

    const result = await handler[command](params);
    return {
      protocol,
      command,
      ...result,
      timestamp: new Date().toISOString(),
      status: 'success'
    };
  }

  initializeProtocols() {
    ${config.protocols.filter(p => p.enabled).map(p => `
    // Initialize ${p.name}
    try {
      const ${p.type.replace('-', '_')} = new ${p.type.replace('-', '_')}Handler(this.config.protocols.find(p => p.id === '${p.id}'));
      this.protocolHandlers.set('${p.type}', ${p.type.replace('-', '_')});
      console.log('✅ ${p.name} protocol initialized');
    } catch (error) {
