 * Modbus TCP Protocol Handler
 * Generated for: ${protocol.name}
 */

const ModbusRTU = require('modbus-serial');

class ModbusTcpHandler {
  constructor(config) {
    this.config = config;
    this.clients = new Map();
    this.isConnected = false;
  }

  async getClient(deviceIp, port = 502) {
    const key = \`\${deviceIp}:\${port}\`;

    if (!this.clients.has(key)) {
      const client = new ModbusRTU();
      await client.connectTCP(deviceIp, { port });
      this.clients.set(key, client);

      client.on('error', (error) => {
        console.error(\`Modbus error for \${key}:\`, error);
        this.clients.delete(key);
      });
    }

    return this.clients.get(key);
  }

  async readHoldingRegisters({ deviceIp, port = 502, slaveId = 1, startAddress, quantity }) {
    try {
      const client = await this.getClient(deviceIp, port);
      client.setID(slaveId);

      const result = await client.readHoldingRegisters(startAddress, quantity);

      return {
        startAddress,
        quantity,
        values: result.data,
        deviceIp,
        port,
        slaveId
      };
    } catch (error) {
      throw new Error(\`Failed to read holding registers: \${error.message}\`);
    }
  }

  async writeSingleRegister({ deviceIp, port = 502, slaveId = 1, address, value }) {
    try {
      const client = await this.getClient(deviceIp, port);
      client.setID(slaveId);

      await client.writeRegister(address, value);

      return {
        address,
        value,
        deviceIp,
        port,
        slaveId
      };
    } catch (error) {
      throw new Error(\`Failed to write register: \${error.message}\`);
    }
  }

  async readCoils({ deviceIp, port = 502, slaveId = 1, startAddress, quantity }) {
    try {
      const client = await this.getClient(deviceIp, port);
      client.setID(slaveId);

      const result = await client.readCoils(startAddress, quantity);

      return {
        startAddress,
        quantity,
        values: result.data,
        deviceIp,
        port,
        slaveId
      };
    } catch (error) {
      throw new Error(\`Failed to read coils: \${error.message}\`);
    }
  }

  async writeSingleCoil({ deviceIp, port = 502, slaveId = 1, address, value }) {
    try {
      const client = await this.getClient(deviceIp, port);
      client.setID(slaveId);

      await client.writeCoil(address, value);

      return {
        address,
        value,
        deviceIp,
        port,
        slaveId
      };
    } catch (error) {
      throw new Error(\`Failed to write coil: \${error.message}\`);
    }
  }

  getStatus() {
    return {
      connected: this.clients.size > 0,
      activeConnections: this.clients.size,
      devices: Array.from(this.clients.keys())
    };
  }

  close() {
    this.clients.forEach((client, key) => {
      console.log(\`Closing Modbus connection to \${key}\`);
      client.close();
    });
    this.clients.clear();
  }
}

module.exports = ModbusTcpHandler;
`;
