// Server code generation utilities for Gateway Builder
import JSZip from 'jszip';

export interface GatewayConfig {
  name: string;
  description: string;
  version: string;
  protocols: ProtocolConfig[];
  server: {
    port: number;
    host: string;
    ssl: boolean;
    authentication: boolean;
  };
  logging: {
    level: 'debug' | 'info' | 'warn' | 'error';
    file: boolean;
    console: boolean;
  };
}

export interface ProtocolConfig {
  id: string;
  name: string;
  type: 'modbus-tcp' | 'modbus-rtu' | 'modbus-serial' | 'opcua' | 'mqtt' | 'http-rest' | 'ethernet-ip' | 'bacnet' | 'profinet';
  enabled: boolean;
  mode: 'client' | 'server';
  settings: Record<string, any>;
}

export async function generateServerFiles(config: GatewayConfig): Promise<Record<string, string>> {
  const files: Record<string, string> = {};

  // Generate package.json
  files['package.json'] = generatePackageJson(config);

  // Generate main server file
  files['server.js'] = generateServerJs(config);

  // Generate configuration file
  files['config.json'] = JSON.stringify(config, null, 2);

  // Generate protocol handlers
  config.protocols.forEach(protocol => {
    if (protocol.enabled) {
      files[`protocols/${protocol.type}.js`] = generateProtocolHandler(protocol);
    }
  });

  // Generate README
  files['README.md'] = generateReadme(config);

  // Generate Docker files for deployment
  files['Dockerfile'] = generateDockerfile(config);
  files['docker-compose.yml'] = generateDockerCompose(config);

  // Generate startup scripts
  files['start.bat'] = generateStartupScript(config, 'windows');
  files['start.sh'] = generateStartupScript(config, 'linux');

  return files;
}

function generatePackageJson(config: GatewayConfig): string {
  const dependencies: Record<string, string> = {
    'express': '^4.18.2',
    'ws': '^8.14.2',
    'cors': '^2.8.5',
    'helmet': '^7.0.0'
  };

  // Add protocol-specific dependencies
  config.protocols.forEach(protocol => {
    if (!protocol.enabled) return;

    switch (protocol.type) {
      case 'modbus-tcp':
      case 'modbus-rtu':
        dependencies['modbus-serial'] = '^8.0.16';
        break;
      case 'opcua':
        dependencies['node-opcua'] = '^2.106.0';
        break;
      case 'mqtt':
        dependencies['mqtt'] = '^5.0.0';
        break;
    }
  });

  return JSON.stringify({
    name: config.name.toLowerCase().replace(/[^a-z0-9]/g, '-'),
    version: config.version,
    description: config.description,
    main: 'server.js',
    scripts: {
      start: 'node server.js',
      dev: 'nodemon server.js',
      build: 'echo "No build step required"',
      docker: 'docker build -t gateway-server .',
      'docker-run': 'docker run -p 8080:8080 gateway-server'
    },
    dependencies,
    devDependencies: {
      'nodemon': '^3.0.1'
    },
    keywords: ['gateway', 'industrial', 'modbus', 'opcua', 'mqtt', 'automation'],
    author: 'Gateway Builder',
    license: 'MIT'
  }, null, 2);
}

function generateServerJs(config: GatewayConfig): string {
  return `/**
 * ${config.name}
 * ${config.description}
 * 
 * Generated by Gateway Builder
 * Version: ${config.version}
 */

const express = require('express');
const WebSocket = require('ws');
const cors = require('cors');
const helmet = require('helmet');
const path = require('path');

// Protocol handlers
${config.protocols.filter(p => p.enabled).map(p => 
  `const ${p.type.replace('-', '_')}Handler = require('./protocols/${p.type}');`
).join('\n')}

class GatewayServer {
  constructor() {
    this.config = require('./config.json');
    this.app = express();
    this.setupMiddleware();
    this.setupRoutes();
    this.setupWebSocket();
    this.protocolHandlers = new Map();
    this.initializeProtocols();
  }

  setupMiddleware() {
    this.app.use(helmet());
    this.app.use(cors());
    this.app.use(express.json());
    this.app.use(express.static('public'));
  }

  setupRoutes() {
    // Health check endpoint
    this.app.get('/health', (req, res) => {
      res.json({
        status: 'healthy',
        timestamp: new Date().toISOString(),
        uptime: process.uptime(),
        protocols: Array.from(this.protocolHandlers.keys())
      });
    });

    // Configuration endpoint
    this.app.get('/config', (req, res) => {
      res.json(this.config);
    });

    // Protocol status endpoint
    this.app.get('/protocols', (req, res) => {
      const protocols = [];
      this.protocolHandlers.forEach((handler, type) => {
        protocols.push({
          type,
          status: handler.getStatus ? handler.getStatus() : 'unknown',
          enabled: true
        });
      });
      res.json(protocols);
    });

    // REST API for direct protocol access
    this.app.post('/api/:protocol/:action', async (req, res) => {
      try {
        const { protocol, action } = req.params;
        const handler = this.protocolHandlers.get(protocol);
        
        if (!handler) {
          return res.status(404).json({ error: \`Protocol \${protocol} not found\` });
        }

        if (!handler[action]) {
          return res.status(400).json({ error: \`Action \${action} not supported for \${protocol}\` });
        }

        const result = await handler[action](req.body);
        res.json(result);
      } catch (error) {
        console.error('API Error:', error);
        res.status(500).json({ error: error.message });
      }
    });
  }

  setupWebSocket() {
    this.wss = new WebSocket.Server({ 
      port: ${config.server.port + 1},
      path: '/ws'
    });

    console.log(\`🔌 WebSocket server started on ws://localhost:\${${config.server.port + 1}}/ws\`);

    this.wss.on('connection', (ws, req) => {
      console.log('📱 New WebSocket client connected');
      
      ws.on('message', async (message) => {
        try {
          const data = JSON.parse(message);
          const response = await this.handleWebSocketMessage(data);
          ws.send(JSON.stringify(response));
        } catch (error) {
          console.error('WebSocket Error:', error);
          ws.send(JSON.stringify({
            error: error.message,
            timestamp: new Date().toISOString()
          }));
        }
      });

      ws.on('close', () => {
        console.log('📱 WebSocket client disconnected');
      });
    });
  }

  async handleWebSocketMessage(data) {
    const { protocol, command, ...params } = data;
    
    const handler = this.protocolHandlers.get(protocol);
    if (!handler) {
      throw new Error(\`Protocol \${protocol} not found\`);
    }

    if (!handler[command]) {
      throw new Error(\`Command \${command} not supported for \${protocol}\`);
    }

    const result = await handler[command](params);
    return {
      protocol,
      command,
      ...result,
      timestamp: new Date().toISOString(),
      status: 'success'
    };
  }

  initializeProtocols() {
    ${config.protocols.filter(p => p.enabled).map(p => `
    // Initialize ${p.name}
    try {
      const ${p.type.replace('-', '_')} = new ${p.type.replace('-', '_')}Handler(this.config.protocols.find(p => p.id === '${p.id}'));
      this.protocolHandlers.set('${p.type}', ${p.type.replace('-', '_')});
      console.log('✅ ${p.name} protocol initialized');
    } catch (error) {
      console.error('❌ Failed to initialize ${p.name}:', error);
    }`).join('\n')}
  }

  start() {
    const port = this.config.server.port;
    const host = this.config.server.host;

    this.server = this.app.listen(port, host, () => {
      console.log(\`🚀 \${this.config.name} started\`);
      console.log(\`📡 HTTP Server: http://\${host}:\${port}\`);
      console.log(\`🔌 WebSocket Server: ws://\${host}:\${port + 1}/ws\`);
      console.log(\`📊 Health Check: http://\${host}:\${port}/health\`);
      console.log(\`⚙️  Configuration: http://\${host}:\${port}/config\`);
    });
  }

  stop() {
    if (this.server) {
      this.server.close();
    }
    if (this.wss) {
      this.wss.close();
    }
    
    // Close protocol connections
    this.protocolHandlers.forEach((handler) => {
      if (handler.close) {
        handler.close();
      }
    });
  }
}

// Create and start server
const gateway = new GatewayServer();
gateway.start();

// Graceful shutdown
process.on('SIGINT', () => {
  console.log('\\n🛑 Shutting down gateway server...');
  gateway.stop();
  process.exit(0);
});

process.on('SIGTERM', () => {
  console.log('🛑 Received SIGTERM, shutting down...');
  gateway.stop();
  process.exit(0);
});

module.exports = GatewayServer;
`;
}

function generateProtocolHandler(protocol: ProtocolConfig): string {
  switch (protocol.type) {
    case 'modbus-tcp':
      return generateModbusTcpHandler(protocol);
    case 'opcua':
      return generateOpcuaHandler(protocol);
    case 'mqtt':
      return generateMqttHandler(protocol);
    default:
      return generateGenericHandler(protocol);
  }
}

function generateModbusTcpHandler(protocol: ProtocolConfig): string {
  return `/**
 * Modbus TCP Protocol Handler
 * Generated for: ${protocol.name}
 */

const ModbusRTU = require('modbus-serial');

class ModbusTcpHandler {
  constructor(config) {
    this.config = config;
    this.clients = new Map();
    this.isConnected = false;
  }

  async getClient(deviceIp, port = 502) {
    const key = \`\${deviceIp}:\${port}\`;
    
    if (!this.clients.has(key)) {
      const client = new ModbusRTU();
      await client.connectTCP(deviceIp, { port });
      this.clients.set(key, client);
      
      client.on('error', (error) => {
        console.error(\`Modbus error for \${key}:\`, error);
        this.clients.delete(key);
      });
    }
    
    return this.clients.get(key);
  }

  async readHoldingRegisters({ deviceIp, port = 502, slaveId = 1, startAddress, quantity }) {
    try {
      const client = await this.getClient(deviceIp, port);
      client.setID(slaveId);
      
      const result = await client.readHoldingRegisters(startAddress, quantity);
      
      return {
        startAddress,
        quantity,
        values: result.data,
        deviceIp,
        port,
        slaveId
      };
    } catch (error) {
      throw new Error(\`Failed to read holding registers: \${error.message}\`);
    }
  }

  async writeSingleRegister({ deviceIp, port = 502, slaveId = 1, address, value }) {
    try {
      const client = await this.getClient(deviceIp, port);
      client.setID(slaveId);
      
      await client.writeRegister(address, value);
      
      return {
        address,
        value,
        deviceIp,
        port,
        slaveId
      };
    } catch (error) {
      throw new Error(\`Failed to write register: \${error.message}\`);
    }
  }

  async readCoils({ deviceIp, port = 502, slaveId = 1, startAddress, quantity }) {
    try {
      const client = await this.getClient(deviceIp, port);
      client.setID(slaveId);
      
      const result = await client.readCoils(startAddress, quantity);
      
      return {
        startAddress,
        quantity,
        values: result.data,
        deviceIp,
        port,
        slaveId
      };
    } catch (error) {
      throw new Error(\`Failed to read coils: \${error.message}\`);
    }
  }

  async writeSingleCoil({ deviceIp, port = 502, slaveId = 1, address, value }) {
    try {
      const client = await this.getClient(deviceIp, port);
      client.setID(slaveId);
      
      await client.writeCoil(address, value);
      
      return {
        address,
        value,
        deviceIp,
        port,
        slaveId
      };
    } catch (error) {
      throw new Error(\`Failed to write coil: \${error.message}\`);
    }
  }

  getStatus() {
    return {
      connected: this.clients.size > 0,
      activeConnections: this.clients.size,
      devices: Array.from(this.clients.keys())
    };
  }

  close() {
    this.clients.forEach((client, key) => {
      console.log(\`Closing Modbus connection to \${key}\`);
      client.close();
    });
    this.clients.clear();
  }
}

module.exports = ModbusTcpHandler;
`;
}

