export async function packageAsExecutable(files: Record<string, string>, config: GatewayConfig): Promise<Blob> {
  const zip = new JSZip();

  // Add all generated files to ZIP
  Object.entries(files).forEach(([filename, content]) => {
    if (filename.includes('/')) {
      // Handle directory structure
      zip.file(filename, content);
    } else {
      zip.file(filename, content);
    }
  });

  // Generate the ZIP file
  const blob = await zip.generateAsync({ 
    type: 'blob',
    compression: 'DEFLATE',
    compressionOptions: { level: 6 }
  });

  return blob;
}

export function downloadGeneratedServer(config: GatewayConfig, blob: Blob): void {
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = `${config.name.toLowerCase().replace(/[^a-z0-9]/g, '-')}-gateway-v${config.version}.zip`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
}
